// v3.27.1: unified recommend-cache key resolver. Defaults use the provider
// name (which equals the id for the built-in 6); customs use the AI's
// generated id. Lets buildModelSelector and recheckModelForAI share one
// lookup convention regardless of AI type.
function getCacheIdForAI(aiId) {
  const isDefault = !!DEFAULT_AIS.find(d => d.id === aiId);
  return isDefault ? `default-${aiId}` : `custom-${aiId}`;
}

// v3.32.10 — helpers to fetch role-specific cached recommendations.
// Returns the cached payload (with `model`, `why`, `labels`, optional `none`)
// or null. Also handles legacy migration: if a pre-v3.32.10 single cache key
// exists and the new role-specific keys do not, the legacy is treated as the
// Reviewer cache (matches the historic implicit role) so users see something
// useful while waiting for fresh recommendations to populate.
function getReviewerRecommendation(aiId) {
  const baseId = getCacheIdForAI(aiId);
  const reviewerCache = getCachedRecommendation(`${baseId}-reviewer`);
  if (reviewerCache) return reviewerCache;
  // Legacy migration: pre-v3.32.10 cache stored a single recommendation
  // under the unsuffixed key. Treat it as the Reviewer pick until refreshed.
  const legacy = getCachedRecommendation(baseId);
  return legacy || null;
}
function getBuilderRecommendation(aiId) {
  return getCachedRecommendation(`${getCacheIdForAI(aiId)}-builder`);
}

function _isContentFilteredSignal(value) {
  const s = (value == null ? '' : String(value)).toUpperCase();
  return /CONTENT[_\s-]?FILTER|\bSAFETY\b|BLOCK_REASON|PROMPT[_\s-]?BLOCK|BLOCKED|PROHIBITED/.test(s);
}

function _makeContentFilteredError(ai, reason) {
  const suffix = reason ? ` (${reason})` : '';
  const err = new Error(`CONTENT_FILTERED: ${ai?.name || 'Builder'} output was blocked by the provider${suffix}`);
  err.code = 'CONTENT_FILTERED';
  err.contentFiltered = true;
  return err;
}

function isContentFilteredError(err) {
  return !!(err && (err.contentFiltered || err.code === 'CONTENT_FILTERED' || _isContentFilteredSignal(err.message)));
}

function buildModelSelector(aiId, provider, currentModel, showRecheck = false) {
  const models = getModelsForProvider(provider);
  if (!models.length) return '';

  // v3.32.10 — read TWO cached recommendations: Reviewer (✨) and Builder (🔨).
  // The dropdown surfaces both so users see the right pick for each role
  // their AI might be slotted into. Reasoning models flagged for the
  // Reviewer role show a small "Reasoning — slower/pricier" badge in the
  // option text since the Reviewer prompt allows them when genuinely best.
  const reviewerCache = getReviewerRecommendation(aiId);
  const builderCache  = getBuilderRecommendation(aiId);
  const reviewerModel = reviewerCache?.model || null;
  const builderModel  = builderCache?.model  || null;
  const reviewerWhy   = reviewerCache?.why   || '';
  const builderWhy    = builderCache?.why    || '';

  const isReasoningLike = (m) => BUILDER_DISALLOWED_PATTERN.test(m);

  // v3.63.32 — Custom dropdown rows. Native <option> can't be background-tinted
  // in Chrome, so the picker is a custom combobox: each row carries the role
  // markers as colored words AND a tint class so the ✨ Reviewer (gold) and
  // 🔨 Builder (blue) picks pop the moment the list opens. A shared inner
  // builder keeps the trigger's current-value display identical to its row.
  const _optInner = (m) => {
    const spans = [];
    if (m === reviewerModel) spans.push('<span class="opt-role is-reviewer">✨ Reviewer</span>');
    if (m === builderModel)  spans.push('<span class="opt-role is-builder">🔨 Builder</span>');
    // v3.63.132 — Reviewer-only warning. Surfaces in the dropdown so users
    // see WHY they shouldn't pick this model as Builder — and still can if
    // they really mean to (e.g. they've raised the cap server-side and
    // want to override our guard).
    if (isBuilderIncapableModel(m)) spans.push('<span class="opt-role is-builder-warn" title="Output token cap too low to finish a Builder round — use as Reviewer only">⚠️ Reviewer-only</span>');
    const markerHTML = spans.length ? spans.join(' · ') + ' — ' : '';
    const reasoningBadge = (m === reviewerModel && isReasoningLike(m)) ? ' (reasoning)' : '';
    return `${markerHTML}${esc(m)}${reasoningBadge}`;
  };
  const _tintCls = (m) => {
    const r = m === reviewerModel, b = m === builderModel;
    const w = isBuilderIncapableModel(m);
    return (r && b) ? ' is-both-pick' : r ? ' is-reviewer-pick' : b ? ' is-builder-pick' : w ? ' is-builder-warn-pick' : '';
  };
  const optRows = models.map(m =>
    `<div class="model-select-opt${_tintCls(m)}${m === currentModel ? ' is-selected' : ''}" role="option" data-value="${escapeHtml(m)}" onclick="wfModelSelectPick(this, event)">${_optInner(m)}</div>`
  ).join('');
  // Current-value display: matches the chosen row, or the raw id when the saved
  // model isn't in the live list (e.g. it was quarantined / removed).
  const valueInner = models.includes(currentModel)
    ? _optInner(currentModel)
    : esc(currentModel || '(pick a model)');

  // Note line: shows the WHY for BOTH role recommendations whenever they're
  // cached — independent of which model the user currently has selected.
  // Each role renders on its own line via .model-select-note-line { display: block; }.
  // Model id is included in parens so users can confirm cache integrity.
  // v3.32.11 — switched from inline ' · ' separator to per-line spans
  // because long WHY text from BOTH roles concatenated mid-sentence
  // produced awkward wrapping. Each role on its own line is cleaner.
  // v3.32.12 — dropped the currentModel === reviewerModel/builderModel
  // gate. The notes describe what was RECOMMENDED for each role; they
  // should be visible whether the user has selected the recommended
  // model or some other one. Previously, picking the Reviewer pick hid
  // the Builder reasoning (and vice versa), which obscured the Builder
  // recommendation entirely whenever the two roles diverged on lineup
  // (Gemini, Grok, Mistral all hit this on the v3.32.11 first run).
  const noteParts = [];
  if (reviewerModel && reviewerWhy) {
    noteParts.push(`<span class="model-select-note-line is-reviewer">✨ Reviewer (${esc(reviewerModel)}): ${esc(reviewerWhy)}</span>`);
  }
  if (builderModel && builderWhy) {
    noteParts.push(`<span class="model-select-note-line is-builder">🔨 Builder (${esc(builderModel)}): ${esc(builderWhy)}</span>`);
  }
  // NONE handling — if the AI flagged NONE for Builder (no model on its
  // lineup is suitable as a Builder), surface that so users know why no
  // 🔨 marker appears in the dropdown. Only show when no actual Builder
  // pick is cached.
  if (!builderModel && builderCache?.none && builderCache?.why) {
    noteParts.push(`<span class="model-select-note-line is-builder">🔨 Builder: ${esc(builderCache.why)}</span>`);
  }
  const noteHtml = noteParts.length ? `<span class="model-select-note">${noteParts.join('')}</span>` : '';

  // v3.32.10 — recheck button label updated to reflect dual-role behavior.
  const recheckBtn = showRecheck
    ? `<button class="ai-recheck-btn" id="recheckbtn-${aiId}" onclick="recheckModelForAI('${aiId}')" title="Ask the provider for its best Reviewer and Builder models AND classify Cheap / Balanced / Thinker / Fast tier picks — populates all 6 cards on the hive grid">Recommend Models</button>`
    : '';

  return `<div class="model-select-wrap">
    <span class="model-select-label">Pick a model:</span>
    <div class="model-select model-select-custom" id="modelsel-${aiId}" data-value="${escapeHtml(currentModel || '')}"
      tabindex="0" role="combobox" aria-haspopup="listbox" aria-expanded="false"
      onclick="wfModelSelectToggle(this, event)"
      onkeydown="wfModelSelectKey(this, event)">
      <span class="model-select-value">${valueInner}</span>
      <span class="model-select-arrow" aria-hidden="true">▾</span>
      <div class="model-select-list" role="listbox">${optRows}</div>
    </div>
    ${recheckBtn}
    ${noteHtml}
  </div>`;
}

// v3.63.32 — Custom model-dropdown behavior (open/close, outside-click, pick,
// keyboard). The trigger keeps id="modelsel-<aiId>" + data-value so the value
// contract (Fix-Worker-Bee flash/scroll) is unchanged; selection writes
// data-value and calls saveModelForAI, matching the old <select> onchange.
// Arrow-key option navigation is intentionally deferred to a follow-up —
// click + Enter/Space/Esc cover v1.
function wfModelSelectToggle(trigger, ev) {
  if (ev) ev.stopPropagation();
  const wasOpen = trigger.classList.contains('is-open');
  wfModelSelectCloseAll();
  if (!wasOpen) {
    trigger.classList.add('is-open');
    trigger.setAttribute('aria-expanded', 'true');
    // v3.63.33 — the list is position:fixed; place it from the trigger's live
    // rect so it escapes the Worker Bees scroll container and the modal
    // backdrop-filter clip that otherwise trapped/under-rendered it.
    wfModelSelectPosition(trigger);
    const sel = trigger.querySelector('.model-select-opt.is-selected');
    if (sel) sel.scrollIntoView({ block: 'nearest' });
    // A fixed list can't track the trigger, so close on the next scroll/resize.
    window.addEventListener('scroll', wfModelSelectCloseAll, { capture: true, once: true });
    window.addEventListener('resize', wfModelSelectCloseAll, { once: true });
  }
}
// v3.63.33 — anchor the fixed list to the trigger; flip up when there isn't
// room below so it never spills off the bottom of the viewport.
function wfModelSelectPosition(trigger) {
  const list = trigger.querySelector('.model-select-list');
  if (!list) return;
  const r = trigger.getBoundingClientRect();
  list.style.left  = r.left + 'px';
  list.style.width = r.width + 'px';
  const spaceBelow = window.innerHeight - r.bottom;
  const needed = Math.min(list.scrollHeight || 320, 320) + 8;
  if (spaceBelow < needed && r.top > spaceBelow) {
    list.style.top = '';
    list.style.bottom = (window.innerHeight - r.top + 4) + 'px';
  } else {
    list.style.bottom = '';
    list.style.top = (r.bottom + 4) + 'px';
  }
}
function wfModelSelectPick(opt, ev) {
  if (ev) ev.stopPropagation();
  const trigger = opt.closest('.model-select-custom');
  if (!trigger) return;
  const m = opt.dataset.value;
  const aiId = trigger.id.slice('modelsel-'.length);
  trigger.dataset.value = m;
  const valEl = trigger.querySelector('.model-select-value');
  if (valEl) valEl.innerHTML = opt.innerHTML;
  trigger.querySelectorAll('.model-select-opt.is-selected').forEach(o => o.classList.remove('is-selected'));
  opt.classList.add('is-selected');
  trigger.classList.remove('is-open');
  trigger.setAttribute('aria-expanded', 'false');
  if (typeof saveModelForAI === 'function' && aiId) saveModelForAI(aiId, m);
}
function wfModelSelectKey(trigger, ev) {
  // v3.63.34 — full keyboard nav, restoring the native <select> feel:
  // closed  -> Enter/Space/Down/Up opens and highlights the current pick
  // open     -> Up/Down move the highlight (wrap), Home/End jump, Enter commits,
  //             Esc/Tab close.
  const k = ev.key;
  const isOpen = trigger.classList.contains('is-open');
  if (!isOpen) {
    if (k === 'Enter' || k === ' ' || k === 'Spacebar' || k === 'ArrowDown' || k === 'ArrowUp') {
      ev.preventDefault();
      wfModelSelectToggle(trigger, ev);
      wfModelSelectSetActiveFromSelected(trigger);
    }
    return;
  }
  if (k === 'Escape' || k === 'Tab') {
    if (k === 'Escape') ev.preventDefault();
    wfModelSelectCloseAll();
    return;
  }
  const opts = Array.from(trigger.querySelectorAll('.model-select-opt'));
  if (!opts.length) return;
  let i = opts.findIndex(o => o.classList.contains('is-active'));
  if (k === 'ArrowDown') {
    ev.preventDefault(); wfModelSelectActivate(opts, i < 0 ? 0 : (i + 1) % opts.length);
  } else if (k === 'ArrowUp') {
    ev.preventDefault(); wfModelSelectActivate(opts, i <= 0 ? opts.length - 1 : i - 1);
  } else if (k === 'Home') {
    ev.preventDefault(); wfModelSelectActivate(opts, 0);
  } else if (k === 'End') {
    ev.preventDefault(); wfModelSelectActivate(opts, opts.length - 1);
  } else if (k === 'Enter' || k === ' ' || k === 'Spacebar') {
    ev.preventDefault();
    const active = opts[i] || opts.find(o => o.classList.contains('is-selected')) || opts[0];
    if (active) wfModelSelectPick(active, ev);
  }
}
function wfModelSelectActivate(opts, i) {
  opts.forEach(o => o.classList.remove('is-active'));
  const el = opts[i];
  if (el) { el.classList.add('is-active'); el.scrollIntoView({ block: 'nearest' }); }
}
function wfModelSelectSetActiveFromSelected(trigger) {
  const opts = Array.from(trigger.querySelectorAll('.model-select-opt'));
  if (!opts.length) return;
  let i = opts.findIndex(o => o.classList.contains('is-selected'));
  wfModelSelectActivate(opts, i < 0 ? 0 : i);
}
function wfModelSelectCloseAll(e) {
  document.querySelectorAll('.model-select-custom.is-open').forEach(t => {
    if (!e || !t.contains(e.target)) {
      t.classList.remove('is-open');
      t.setAttribute('aria-expanded', 'false');
      t.querySelectorAll('.model-select-opt.is-active').forEach(o => o.classList.remove('is-active'));
    }
  });
}
// One global outside-click closer (idempotent). In-widget clicks stopPropagation
// so they never reach this and can't self-close.
if (typeof window !== 'undefined' && !window._wfModelSelectOutsideBound) {
  window._wfModelSelectOutsideBound = true;
  document.addEventListener('click', wfModelSelectCloseAll);
}

// v3.63.307 — getModelForAI: resolve the model to use for THIS ai object.
// Variants (ai.parentId set) override the shared cfg.model on their ai.model
// field — so two variants of the same provider can run different models while
// sharing one API key + headers + body shape. Parent / non-variant rows fall
// back to cfg.model unchanged. Defined here at the top of the file so every
// render and request path can read through one canonical resolver.
function getModelForAI(ai) {
  if (!ai) return '';
  if (ai.model) return ai.model;
  const cfg = API_CONFIGS[ai.provider];
  return (cfg && cfg.model) || '';
}

function saveModelForAI(aiId, modelId, opts) {
  const ai = aiList.find(a => a.id === aiId);
  if (!ai) return;
  const cfg = API_CONFIGS[ai.provider];
  if (!cfg) return;
  // v3.63.307 — Variants persist their model on the ai object, NOT on the
  // shared API_CONFIGS entry. cfg.model is provider-scoped; if a variant
  // wrote there it would clobber its parent (and any sibling variants).
  // ai.model rides through saveHive -> customAIs serialization since
  // variants always live outside DEFAULT_AIS.
  if (ai.parentId) {
    ai.model = modelId;
  } else {
    cfg.model = modelId;
    // Update Gemini endpoint if needed
    if (ai.provider === 'gemini' && cfg.endpointFn) {
      cfg.endpoint = cfg.endpointFn(modelId);
    }
  }
  saveSettings();
  // v3.63.13 — refresh the row so the new model surfaces in the card header
  // (— gpt-5.5 etc.) immediately, not only after a full grid re-render.
  // v3.63.155 — `opts.keepExpanded === false` skips the auto-add to
  // _expandedAIIds. Called by applyHiveProfile so a bulk profile apply
  // doesn't blow open every row (David's report: "if I use the dropdown
  // at the top of the page to select a profile all the cards open up").
  // `opts.silent === true` suppresses the per-AI toast — also for bulk.
  const _keepExpanded = (opts && opts.keepExpanded === false) ? false : true;
  renderAIRow(aiId, _keepExpanded);
  // v3.32.12 — note re-render removed. As of v3.32.12, the role-recommendation
  // notes are invariant to which model the user has selected — both ✨ Reviewer
  // and 🔨 Builder lines render whenever the caches exist, full stop. Changing
  // the dropdown selection therefore has no effect on the note content, so
  // there's no reason to query the DOM and rewrite it on every change. The
  // note is set once by buildModelSelector at row render time and only
  // refreshes when the entire row is re-rendered (e.g., after Recommend Models
  // populates new caches). Removed for cleanliness, no behavior loss.
  if (!opts || !opts.silent) toast(`✓ ${ai.name} model set to ${modelId}`, 2000);
}

// v3.63.284 — _originalModel scaffold removed. Originally captured at AI
// add/import time to support the ↺ Reset button; that button was removed
// in v3.31.0 (replaced by Best/Fast/Budget buttons, themselves removed in
// v3.32.10 in favor of the ✨ Reviewer / 🔨 Builder dropdown markers).
// The field continued to be written and migrated for "forward-compatibility
// scaffold for any future audit-trail feature" — 33+ releases later that
// feature hasn't materialized, so the writes + the boot-time
// ensureOriginalModelBaseline() migration + the saveHive() it triggered on
// every cold start are all retired together. If an audit-trail UI is ever
// added it can capture the baseline at that moment with no historical
// data lost (nothing was reading the field anyway).

// v3.63.18 — Three one-shot migrations removed (V33210 recommendation cache
// reshuffle, V3605 Together model-list filter change, V3607 Together
// serverless-only URL change). All three shipped between v3.32.10 and v3.60.7
// and finished their job within one page-load of each user. Their localStorage
// sentinels (waxframe_v33210_recommend_migrated, waxframe_v3605_together
// _models_migrated, waxframe_v3607_together_models_migrated) are now swept in
// the orphan-key cleanup at the top of DOMContentLoaded. If a returning user
// somehow reaches v3.63.18+ without ever loading v3.60.7 (extremely unlikely),
// their next dropdown read will trigger a fresh fetch through the current
// parse path and self-heal — no migration needed.


// (both removed in v3.31.0) and the recovery from the legacy removeAI
// function (removed in v3.30.4). The snapshot is still kept because the
// self-heal path remains relevant for users upgrading from pre-v3.26.5
// hives where structural configs may have been destroyed.
//
// We deep-clone so any future mutations to API_CONFIGS at runtime (model
// swaps, recommend updates, etc.) don't pollute the canonical defaults.
// Functions can't survive JSON serialization, so we copy the object shells
// and re-attach the function references afterward.
const DEFAULT_API_CONFIGS = (() => {
  const snapshot = {};
  DEFAULT_AIS.forEach(d => {
    const orig = API_CONFIGS[d.provider];
    if (!orig) return;
    snapshot[d.provider] = {
      ...orig,
      // function refs survive shallow-clone — these are stable closures
    };
  });
  return snapshot;
})();

let aiList           = JSON.parse(JSON.stringify(DEFAULT_AIS)); // full list, active = checked ones
let activeAIs        = [];   // AIs selected in setup
