// v3.63.61 / v3.63.320 — Central round-completion hook. Originally added
// (v3.63.61) as forensic instrumentation for a round-counter bug where
// rounds occasionally jumped non-monotonically (e.g. 6 → 13 with no
// intervening rounds in history) — the ringBuffer + console.warn trail
// pinpoints which call site fires in the gap if the symptom ever recurs.
// As of v3.63.320 this function is ALSO the single dispatch point for the
// auto-backup-after-round hook (every round-completion path on app.js
// already calls _logRoundBump right before incrementing `round`, so the
// auto-backup rides the same wave). The "can be removed once root cause
// is fixed" comment that lived here pre-v3.63.343 was stale on both fronts:
// the auto-backup makes the function load-bearing regardless, and the
// forensic part is cheap enough to leave in as a safety net against
// regression of the original symptom. Don't remove this function.
function _logRoundBump(siteTag) {
  try {
    const from = typeof round === 'number' ? round : null;
    const to = (from == null) ? null : from + 1;
    const msg = `[round-bump] ${siteTag}: ${from} \u2192 ${to}`;
    if (typeof console !== 'undefined' && console.warn) console.warn(msg);
    if (typeof WF_DEBUG !== 'undefined' && Array.isArray(WF_DEBUG.ringBuffer)) {
      WF_DEBUG.ringBuffer.push({
        ts: Date.now(),
        kind: 'round-bump',
        site: siteTag,
        from: from,
        to: to,
        phase: (typeof phase === 'string') ? phase : null,
        historyLen: (typeof history !== 'undefined' && Array.isArray(history)) ? history.length : null
      });
      if (WF_DEBUG.ringBuffer.length > 200) WF_DEBUG.ringBuffer.shift();
    }
  } catch (e) { /* never let instrumentation throw */ }
  // v3.63.320 \u2014 Auto-backup hook. Single central trigger covers every
  // round-completion site (continuing / unanimous / majority / builder-
  // only / apply-decisions-all-bypassed) because they all call
  // _logRoundBump right before incrementing `round`. The hook checks
  // its own preconditions internally (FSA supported, freq>0, round
  // matches cadence, folder handle reachable + permitted) \u2014 silent
  // no-op when any fail. Fire-and-forget so a slow disk write doesn't
  // block the round-counter bump or downstream chain. defined in
  // storage.js; existence check keeps app.js loadable when storage.js
  // hasn't parsed yet (e.g. dev reload mid-edit).
  try {
    if (typeof window !== 'undefined' && typeof window._autoBackupAfterRound === 'function') {
      window._autoBackupAfterRound();
    }
  } catch (e) { /* never let auto-backup throw upward into the round-completion path */ }
}

