// ── UTILS ──
// v3.63.15 — IMPORTANT: `esc()` escapes `& < >` only. It is SAFE for HTML
// TEXT CONTENT (between tags like <div>${esc(x)}</div>) but UNSAFE for HTML
// ATTRIBUTE CONTEXTS (inside onclick="...", title="...", value="...", etc.)
// because it does NOT escape `"` or `'`. For attribute contexts use
// `escapeHtml()` which also escapes quotes. CodeQL flagged five
// attribute-context misuses in this file in v3.63.15; all were swapped to
// `escapeHtml()` at that release. (v3.63.280 — line numbers in the original
// comment had rotted since the file grew ~10k lines; they're now stripped
// in favor of grep-by-symbol if the audit-trail is needed again.)
function esc(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}
// v3.56.38 — href guard. Returns the URL only if it parses as an absolute
// http/https URL; anything else (javascript:, data:, relative, garbage from
// an imported custom-AI object) collapses to '' so it can't fire on click.
// The returned value is still attribute-escaped at the call site. Storage-layer
// import validation is the first line of defense; this is the render-sink belt.
function safeUrl(u) {
  try {
    const p = new URL(String(u ?? ''));
    return (p.protocol === 'http:' || p.protocol === 'https:') ? p.href : '';
  } catch { return ''; }
}
// v3.32.20 — Strip the "[Base] " prefix that's added at module-load to
// default AI names. Used for display in the work-screen hive cards
// where the prefix is visual noise — every base model has it, so it
// isn't differentiating information at the card level. Underlying
// `ai.name` stays unchanged so export, transcript, conflict
// attribution, and the Change Builder modal (where Base vs Custom is
// useful at-a-glance) all continue to see the prefixed form. Use the
// plain `ai.name` everywhere except work-screen cards.
function displayAiName(name) {
  return (name || '').replace(/^\[Base\]\s+/, '');
}
function toast(msg, ms = 5000) {
  // v3.63.330 — default raised from 2800ms to 5000ms. 2.8s was enough for a
  // glance ack but too tight for the longer hive-profile / model-recommend
  // messages that run 70+ characters. Individual callers can still pass
  // shorter or longer ms; this just makes the default readable.
  const t = document.getElementById('toast');
  if (!t) return;
  t.textContent = msg;
  t.classList.add('show');
  clearTimeout(toast._t);
  toast._t = setTimeout(() => t.classList.remove('show'), ms);
}
function setStatus(msg) {
  const el = document.getElementById('statusText');
  if (el) el.textContent = msg;
}

// v3.63.279 — Centralized Smoke-the-Hive label reset. Pre-v3.63.279 this
