// Populate the Backup Builder dropdown from the live hive and sync every
// control to its stored value. Called from goToScreen when entering the
// Settings screen, so it always reflects the current hive + saved prefs.
// v3.63.90 — Settings Storage section: four wipe buttons (localStorage,
// IndexedDB, sessionStorage, all) that call the shared wipe functions in
// storage.js. Each button uses the same two-click confirm pattern help.html
// uses. Idempotent — guards via dataset.wired so re-opening Settings doesn't
// stack listeners. The status line is shown inline below the four rows.
function wireSettingsWipeButtons() {
  const statusRow = document.getElementById('setWipeStatusRow');
  const statusEl  = document.getElementById('setWipeStatus');
  function setStatus(msg, cls) {
    if (!statusEl || !statusRow) return;
    statusEl.textContent = msg;
    statusRow.style.display = msg ? '' : 'none';
    statusEl.style.color = cls === 'warn' ? '#c5832a' : cls === 'err' ? '#b94a3a' : cls === 'ok' ? '#3a7a4a' : '';
  }
  function wire(btnId, origLabel, armedLabel, wipeFn, layerName) {
    const btn = document.getElementById(btnId);
    if (!btn || btn.dataset.wired === '1') return;
    btn.dataset.wired = '1';
    let armTimer = null;
    btn.addEventListener('click', async () => {
      if (btn.dataset.armed !== '1') {
        btn.dataset.armed = '1';
        btn.textContent = armedLabel;
        setStatus(`Click "${origLabel}" again within 5 seconds to wipe ${layerName}.`, 'warn');
        armTimer = setTimeout(() => {
          btn.dataset.armed = '0';
          btn.textContent = origLabel;
          setStatus('Cancelled — no data was removed.', '');
        }, 5000);
        return;
      }
      clearTimeout(armTimer);
      btn.disabled = true;
      try {
        const result = await wipeFn();
        if (result && typeof result.totalRemoved === 'number') {
          const bits = [];
          if (result.localStorage)   bits.push(`localStorage: ${result.localStorage.removed || 0}`);
          if (result.indexedDB)      bits.push(`IndexedDB: ${result.indexedDB.removed ? 'cleared' : 'failed'}`);
          if (result.sessionStorage) bits.push(`sessionStorage: ${result.sessionStorage.removed || 0}`);
          setStatus(`✓ Wiped everything (${bits.join(' · ')}). Reloading in 2 seconds…`, 'ok');
        } else if (result && result.error) {
          btn.disabled = false;
          btn.dataset.armed = '0';
          btn.textContent = origLabel;
          setStatus(`⚠ Wipe failed: ${result.error}`, 'err');
          return;
        } else {
          const n = result.removed || 0;
          setStatus(`✓ Cleared ${layerName} (${n} entr${n === 1 ? 'y' : 'ies'}). Reloading in 2 seconds…`, 'ok');
        }
        setTimeout(() => { window.location.href = 'index.html'; }, 2000);
      } catch (e) {
        btn.disabled = false;
        btn.dataset.armed = '0';
        btn.textContent = origLabel;
        setStatus(`⚠ Wipe failed: ${e && e.message ? e.message : e}`, 'err');
      }
    });
  }
  wire('setWipeLocalStorageBtn',   'Wipe localStorage',   '⚠ Click again within 5s to confirm', window.wipeLocalStorage,   'localStorage');
  wire('setWipeIndexedDBBtn',      'Wipe IndexedDB',      '⚠ Click again within 5s to confirm', window.wipeIndexedDB,      'IndexedDB');
  wire('setWipeSessionStorageBtn', 'Wipe sessionStorage',  '⚠ Click again within 5s to confirm', window.wipeSessionStorage, 'sessionStorage');
  wire('setWipeAllStorageBtn',     'Wipe EVERYTHING',     '⚠ Click again within 5s to confirm FULL WIPE', window.wipeAllStorage, 'all storage');
}

function renderSettings() {
  // Backup Builder dropdown — list every configured AI except the current
  // Builder (a backup that IS the builder is meaningless). Falls back to the
  // full list if no builder is set yet.
  const sel = document.getElementById('setAutoBackupBuilder');
  if (sel) {
    const saved = getAutoBackupBuilder();
    const eligible = (Array.isArray(activeAIs) ? activeAIs : []).filter(a => a.id !== builder);
    sel.innerHTML = '<option value="">None — pause and ask me</option>' +
      eligible.map(a => `<option value="${escapeHtml(a.id)}">${esc(a.name)}</option>`).join('');
    // Restore the saved choice only if that AI is still in the hive; otherwise
    // fall back to None so we never point at a removed AI.
    sel.value = eligible.some(a => a.id === saved) ? saved : '';
    if (sel.value !== saved) localStorage.setItem(AUTO_SETTINGS.backupBuilder.key, sel.value);
  }
  // v3.63.90 — wire the Storage wipe buttons. Idempotent; guards against
  // double-binding when Settings is re-opened. Same shared wipe functions
  // help.html uses (window.wipeLocalStorage etc.), so behavior is identical
  // across both surfaces.
  wireSettingsWipeButtons();
  renderSettingsLicense();
  const toggle = document.getElementById('setAutoNeverDisableBuilder');
  if (toggle) toggle.checked = getAutoNeverDisableBuilder();
  const streak = document.getElementById('setAutoStreakLimit');
  if (streak) streak.value = getAutoStreakLimit();
  const sMult = document.getElementById('setAutoSlowMult');
  if (sMult) sMult.value = getAutoSlowMultiplier();
  const sRounds = document.getElementById('setAutoSlowRounds');
  if (sRounds) sRounds.value = getAutoSlowRounds();
  const reroll = document.getElementById('setAutoRerollAttempts');
  if (reroll) reroll.value = getAutoRerollAttempts();
  // v3.63.133 — Deep Dive toggle in the new Diagnostics section. Reads the
  // canonical state from WF_DEBUG (which loads from localStorage at init).
  // The dev-toolbar toggle and this Settings toggle stay in sync via
  // WF_DEBUG.setDeepDive() which updates both.
  const dd = document.getElementById('setDeepDive');
  if (dd && typeof WF_DEBUG !== 'undefined') dd.checked = !!WF_DEBUG.deepDiveOn;
  // v3.56.12 — Vision/OCR provider picker. List all four vision providers,
  // flagging which are keyed; the saved pick is restored (falls back to
  // Automatic at runtime if it's later un-keyed).
  const vis = document.getElementById('setVisionProvider');
  if (vis) {
    const label = { chatgpt: 'ChatGPT', claude: 'Claude', gemini: 'Gemini', grok: 'Grok' };
    vis.innerHTML = '<option value="">Automatic — first available</option>' +
      VISION_PROVIDERS.map(p => {
        const keyed = !!API_CONFIGS[p]?._key;
        return `<option value="${escapeHtml(p)}">${esc(label[p] || p)}${keyed ? '' : ' (no key)'}</option>`;
      }).join('');
    vis.value = getVisionProviderPref();
  }

  // v3.63.320 — Backup Sync section: folder + frequency + scope. Delegate
  // to storage.js's initBackupSyncSettings so the FSA helpers stay
  // colocated. Existence check keeps this loadable when storage.js
  // hasn't parsed yet.
  if (typeof initBackupSyncSettings === 'function') initBackupSyncSettings();

  // v3.63.321 — Settings TOC + alphabetical section order. David's call:
  // "the settings menu should have two things — one, alphabetical
  // listings; two, like a table of contents at the top that you can
  // jump to, especially as much info as we've crammed in this thing."
  // Both rendered dynamically: scan all .settings-section elements,
  // assign auto-ids if missing, build the TOC at the top of the inner
  // scroll area, and re-append each section in alpha order (appendChild
  // on an in-DOM node moves it). Idempotent — calling this again
  // produces the same alpha order.
  _renderSettingsToc();

  // v3.62.0 — Workflow Toggles section: live mirrors for the two pill
  // toggles. v3.62.1 — Auto-Update Models toggle + interval radio added.
  // (Checkpoint Backup lands in v3.63.0.)
  const lgEl = document.getElementById('setLengthGuardArmed');
  if (lgEl) {
    // Length Guard is project-scoped via window._lengthGuardOverride.
    // The pill reads "armed" when override is false, "off" when true.
    lgEl.checked = !window._lengthGuardOverride;
  }
  const slowEl = document.getElementById('setSlowAlertsEnabled');
  if (slowEl) slowEl.checked = _slowResponderEnabled;
  const auEl = document.getElementById('setAutoUpdateModels');
  if (auEl) auEl.checked = getAutoUpdateModelsEnabled();
  const intervalVal = getAutoUpdateInterval();
  document.querySelectorAll('input[name="setAutoUpdateInterval"]').forEach(r => {
    r.checked = (r.value === intervalVal);
  });
  // Grey out the interval row when Auto-Update is off — the radios are
  // still readable but visibly inert.
  const intervalRow = document.getElementById('setAutoUpdateIntervalRow');
  if (intervalRow) intervalRow.classList.toggle('settings-row-disabled', !getAutoUpdateModelsEnabled());

  // v3.63.299 — Concurrency override rows (one per provider with a saved
  // key AND a finite default cap; everyone else is uncapped already).
  renderConcurrencyOverrides();
}

// v3.63.321 — Settings TOC + alphabetical section order. Pure render-
// time pass — no HTML reshuffle in index.html, no per-section IDs to
// hand-maintain. Walks every .settings-section in the page, assigns an
// auto-id when missing (derived from the section title slug), sorts by
// the title text (with leading emoji stripped so e.g. "🔑 Account &
// License" sorts as "Account & License" → A, not as the emoji code
// point), reorders via appendChild (which MOVES nodes already in the
// DOM, idempotent on repeat calls), and rebuilds the TOC chip strip at
// the top.
//
// David's call after v3.63.320 landed: "the settings menu should have
// two things — one, alphabetical listings; two, like a table of
// contents at the top that you can jump to, especially as much info
// as we've crammed in this thing."
function _renderSettingsToc() {
  const parent = document.querySelector('#screen-settings .hp-section-body');
  if (!parent) return;
  const sections = Array.from(parent.querySelectorAll(':scope > .settings-section'));
  if (!sections.length) return;
  // Helper: alphabetical title (emoji prefix stripped, whitespace trimmed).
  const _alphaTitle = (s) => {
    const raw = s.querySelector('.settings-section-title')?.textContent || s.id || '';
    return raw.replace(/^[^A-Za-z0-9]+/, '').trim().toLowerCase();
  };
  // Ensure each section has an id so the TOC anchors can target it.
  // Slug from the alpha-title so the id is stable across reloads.
  sections.forEach(s => {
    if (s.id) return;
    const slug = _alphaTitle(s).replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '').slice(0, 40) || 'section';
    s.id = 'settings-' + slug;
  });
  // Alphabetical sort. Use the title text (emoji-stripped) as the key.
  sections.sort((a, b) => _alphaTitle(a).localeCompare(_alphaTitle(b)));
  // Build or rebuild the TOC. Re-creating it each open keeps it in sync
  // with whatever sections happen to be in the DOM right now (e.g. if a
  // future release adds or removes one).
  let toc = parent.querySelector(':scope > .settings-toc');
  if (!toc) {
    toc = document.createElement('div');
    toc.className = 'settings-toc';
    parent.insertBefore(toc, parent.firstChild);
  }
  toc.innerHTML =
    '<span class="settings-toc-label">Jump to:</span>' +
    sections.map(s => {
      const title = s.querySelector('.settings-section-title')?.textContent.trim() || s.id;
      // Inline onclick so the scroll behavior is identical across all
      // browsers without a router hash change (which could trigger
      // back-button state in some SPAs).
      const safeId = s.id.replace(/'/g, "\\'");
      return `<a class="settings-toc-link" href="#${escapeHtml(s.id)}" onclick="document.getElementById('${safeId}').scrollIntoView({behavior:'smooth',block:'start'}); return false;">${escapeHtml(title)}</a>`;
    }).join('');
  // Reorder sections alphabetically by moving each one to the end of
  // the parent (appendChild on an already-DOM node MOVES it). TOC stays
  // at position 0 because we re-inserted it as firstChild above; the
  // sections trail after in alpha order.
  sections.forEach(s => parent.appendChild(s));
  // v3.63.322 — Append an "↑ Go to top" link to the end of every
  // section. Saves the user from scrolling all the way back to use
  // the TOC after reading one long section (Diagnostics + Storage are
  // both substantial). Idempotent: if a previous render already added
  // the link, remove and re-add so the latest TOC anchor wins.
  const tocId = toc.id || (toc.id = 'settingsTocAnchor');
  sections.forEach(s => {
    const existing = s.querySelector(':scope > .settings-goto-top');
    if (existing) existing.remove();
    const link = document.createElement('a');
    link.className = 'settings-goto-top';
    link.href = '#' + tocId;
    link.textContent = '↑ Go to top';
    link.onclick = (ev) => {
      ev.preventDefault();
      document.getElementById(tocId)?.scrollIntoView({behavior: 'smooth', block: 'start'});
    };
    s.appendChild(link);
  });
}

// v3.63.299 — Render the per-provider concurrency override rows into the
// Settings panel container. Section is hidden when there are no eligible
// providers (no keys yet, or only providers with no default cap), so the
// rendered UI is always meaningful — no empty "🚦 Concurrency overrides"
// header floating above nothing.
//
// v3.63.301 — Walks activeAIs (not just built-in provider ids in
// PROVIDER_CONCURRENCY_CAPS) so custom AIs added through "Add Custom AI"
// with one of the throttled provider presets (cohere_<ts>, jamba_<ts>,
// together_ai_<ts>, etc.) are eligible too. Each AI maps to its base
// provider via WFProviderModels.baseProviderId, and the UI groups by
// unique base: one row per base provider with at least one keyed AI in
// the hive, regardless of whether that AI is a built-in default or a
// custom variant. Plain-English copy + per-row "Check your limits"
// link out to API_USAGE_URLS so the user can see what their actual tier
// allows before deciding whether to lift the cap.
function renderConcurrencyOverrides() {
  const section   = document.getElementById('settingsConcurrencySection');
  const container = document.getElementById('setConcurrencyOverridesContainer');
  if (!section || !container) return;

  const overrides = _loadConcurrencyOverrides();
  const usageUrls = (typeof window !== 'undefined' && window.API_USAGE_URLS) || {};

  // Walk activeAIs, find every keyed AI whose BASE provider has a finite
  // default cap. Group by base so three Cohere variants surface as one
  // Cohere row, not three.
  const aiList = (typeof activeAIs !== 'undefined' && Array.isArray(activeAIs))
    ? activeAIs
    : (Array.isArray(window.activeAIs) ? window.activeAIs : []);
  const basesWithKey = new Set();
  aiList.forEach(ai => {
    if (!ai || !ai.provider) return;
    const cfg = API_CONFIGS[ai.provider];
    if (!cfg || !cfg._key) return;
    const base = _baseProviderId(ai.provider);
    if (PROVIDER_CONCURRENCY_CAPS[base]) basesWithKey.add(base);
  });

  // Display labels: prefer the catalog's label for that base provider,
  // fall back to a capitalized base id ("cohere" → "Cohere") if catalog
  // not loaded.
  const baseLabel = base => {
    const cfg = API_CONFIGS[base];
    if (cfg && cfg.label) return cfg.label;
    return base.charAt(0).toUpperCase() + base.slice(1);
  };
  const rows = Array.from(basesWithKey).sort((a, b) =>
    baseLabel(a).toLowerCase().localeCompare(baseLabel(b).toLowerCase()));

  if (!rows.length) {
    section.style.display = 'none';
    container.innerHTML = '';
    return;
  }
  section.style.display = '';

  container.innerHTML = rows.map(base => {
    const label    = baseLabel(base);
    const defCap   = PROVIDER_CONCURRENCY_CAPS[base];
    const override = overrides[base];
    const value    = (typeof override === 'number' && isFinite(override) && override > 0) ? String(override) : '';
    const usageUrl = usageUrls[base] || '';
    // v3.63.303 — external-link pill markup per Kai's spec.
    const limitsLink = usageUrl
      ? ' <a class="settings-inline-link external-link" href="' + escapeHtml(usageUrl) + '" target="_blank" rel="noopener noreferrer" title="Open ' + escapeHtml(label) + ' usage / limits page in a new tab">Check your limits<svg class="external-link-icon" viewBox="0 0 24 24" aria-hidden="true" focusable="false"><path d="M14 3h7v7h-2V6.41l-9.29 9.3-1.42-1.42 9.3-9.29H14V3z"></path><path d="M5 5h6v2H7v10h10v-4h2v6H5V5z"></path></svg><span class="sr-only">(opens in a new tab)</span></a>'
      : '';
    return (
      '<div class="settings-row">' +
        '<div class="settings-row-label">' +
          '<span class="settings-row-name">' + esc(label) + '</span>' +
          '<span class="settings-row-help">Default: ' + defCap + ' at a time (safe for free-tier accounts).' + limitsLink + '</span>' +
        '</div>' +
        '<input type="number" min="1" max="100" step="1" placeholder="' + defCap + '" class="settings-number" value="' + value + '" onchange="onConcurrencyOverrideChange(\'' + base + '\', this.value)">' +
      '</div>'
    );
  }).join('');
}

// v3.63.299 — Onchange handler for a single concurrency-override row.
// Persists via _saveConcurrencyOverride (which deletes the entry when the
// value is empty / zero / non-numeric, so "clear the input" cleanly reverts
// to the default). A light toast confirms the save the way other settings
// rows do, so the change is visible without re-reading the page.
//
// v3.63.301 — Argument is the BASE provider id (cohere / mistral / …), not
// the literal API_CONFIGS key — the override is shared across all variants
// of that base. The toast label comes from baseLabel() rather than directly
// from API_CONFIGS so custom-only hives still get a clean name.
function onConcurrencyOverrideChange(baseProvider, value) {
  _saveConcurrencyOverride(baseProvider, value);
  const cfg   = API_CONFIGS[baseProvider];
  const label = (cfg && cfg.label) || (baseProvider.charAt(0).toUpperCase() + baseProvider.slice(1));
  const num   = Number(value);
  if (!value || !isFinite(num) || num <= 0) {
    toast(`↺ ${label} concurrency: back to default (${PROVIDER_CONCURRENCY_CAPS[baseProvider]})`, 2500);
  } else {
    toast(`✓ ${label} concurrency cap → ${Math.floor(num)} at a time`, 2500);
  }
}

// Save handlers — each fires on the control's change event, persists to
// localStorage, and gives a light toast so the save is visible.
function saveAutoBackupBuilder(val) {
  localStorage.setItem(AUTO_SETTINGS.backupBuilder.key, val || '');
  const name = (activeAIs.find(a => a.id === val) || {}).name;
  toast(val ? `⚡ Failover Builder set to ${name}` : '⚡ Failover Builder: none (Auto will pause and ask)', 3000);
}
function saveAutoNeverDisableBuilder(checked) {
  localStorage.setItem(AUTO_SETTINGS.neverDisableBuilder.key, checked ? 'true' : 'false');
  toast(checked ? '⚡ Builder will never be auto-disabled' : '⚡ Builder can be auto-disabled if it fails', 3000);
}
function saveAutoStreakLimit(val) {
  let n = parseInt(val, 10);
  if (!Number.isFinite(n) || n < 1) n = 1;
  if (n > 10) n = 10;
  localStorage.setItem(AUTO_SETTINGS.streakLimit.key, String(n));
  const el = document.getElementById('setAutoStreakLimit'); if (el) el.value = n;
  toast(`⚡ Failure-streak limit: ${n}`, 2500);
}
function saveAutoSlowMult(val) {
  let n = parseFloat(val);
  if (!Number.isFinite(n) || n < 2) n = 2;
  if (n > 10) n = 10;
  localStorage.setItem(AUTO_SETTINGS.slowMult.key, String(n));
  const el = document.getElementById('setAutoSlowMult'); if (el) el.value = n;
  toast(`⚡ Slow threshold: ${n}× round average`, 2500);
}
function saveAutoSlowRounds(val) {
  let n = parseInt(val, 10);
  if (!Number.isFinite(n) || n < 1) n = 1;
  if (n > 5) n = 5;
  localStorage.setItem(AUTO_SETTINGS.slowRounds.key, String(n));
  const el = document.getElementById('setAutoSlowRounds'); if (el) el.value = n;
  toast(`⚡ Slow threshold: ${n} round${n === 1 ? '' : 's'} in a row`, 2500);
}
function saveAutoRerollAttempts(val) {
  let n = parseInt(val, 10);
  if (!Number.isFinite(n) || n < 1) n = 1;
  if (n > 5) n = 5;
  localStorage.setItem(AUTO_SETTINGS.rerollAttempts.key, String(n));
  const el = document.getElementById('setAutoRerollAttempts'); if (el) el.value = n;
  toast(`⚡ Length-guard reround attempts: ${n}`, 2500);
}

// Restore every Auto Mode setting to its built-in default, then re-sync the
// controls so the UI reflects the reset immediately.
async function resetAutoSettings() {
  const ok = await wfConfirm(
    'Reset Auto settings',
    'Reset all Auto Mode settings to their defaults? This restores Failover Builder (none), Never disable Builder (off), Failure-streak limit (2), Slow threshold (3× / 2 rounds), and Reround attempts (2).',
    { okText: 'Reset to defaults', cancelText: 'Cancel' }
  );
  if (!ok) return;
  Object.values(AUTO_SETTINGS).forEach(s => localStorage.setItem(s.key, s.def));
  renderSettings();
  toast('↺ Auto settings reset to defaults', 3000);
  consoleLog('👤 You reset Auto Mode settings to defaults.', 'info');
}

// ============================================================
//  v3.62.0 — Workflow Toggles settings (Length Guard + Slow
//  Alerts pill mirrors). Auto-Update Models + Checkpoint Backup
//  deferred to v3.62.1 / v3.63.0.
// ============================================================

// Settings-panel handler — routes through the existing toggleLengthGuard()
// so the confirm-modal flow is identical to clicking the footer pill. The
// checkbox in Settings reflects the "armed" state (true = armed, false =
// off); since toggleLengthGuard() flips the *override* (true = off), we
// only fire it when the user-driven change actually wants a flip.
async function settingsToggleLengthGuard(wantArmed) {
  const currentlyArmed = !window._lengthGuardOverride;
  if (wantArmed === currentlyArmed) return;
  await toggleLengthGuard();
  // toggleLengthGuard() may bail at the confirm step — re-sync the
  // checkbox in case the user cancelled out and we need to flip back.
  const el = document.getElementById('setLengthGuardArmed');
  if (el) el.checked = !window._lengthGuardOverride;
}

// Settings-panel handler — routes through toggleSlowResponder() so the
// console log + toast + label/title update happen exactly as they do
// when the user clicks the footer pill. Slow Alerts is a global pref
// (no confirm step), so this is a direct passthrough.
function settingsToggleSlowAlerts(wantOn) {
  if (wantOn === _slowResponderEnabled) return;
  toggleSlowResponder();
  // Defensive re-sync (in case toggleSlowResponder's side effects
  // recompute the state in an order we don't control).
  const el = document.getElementById('setSlowAlertsEnabled');
  if (el) el.checked = _slowResponderEnabled;
}

// ============================================================
//  v3.62.1 — Auto-Update Model Lists
//
//  Background scheduler that re-fetches every configured AI's model
//  list at a user-chosen interval (24h / 1 week / 30 days). Fires on
//  work-screen entry and then at the interval if the user stays. Pure
//  list refresh — does NOT change the user's picked model (recheck is
//  the explicit-action path for that). If a previously-selected model
//  is no longer in a provider's list after refresh, a toast surfaces
//  the retirement.
//
//  When the preference is OFF, model lists persist until the user
//  clicks ↻ Recheck on an AI row. (No real "7-day TTL" existed in the
//  codebase before this — the cache lived forever; this release makes
//  Auto-Update the single intentional source of refresh.)
// ============================================================

const AUTO_UPDATE_INTERVALS = {
  '24h': 24 * 60 * 60 * 1000,
  '1w':  7  * 24 * 60 * 60 * 1000,
  '30d': 30 * 24 * 60 * 60 * 1000,
};
const AUTO_UPDATE_DEFAULT_INTERVAL = '1w';
const AUTO_UPDATE_LAST_RUN_KEY     = 'waxframe_auto_update_last_run';

// Auto-Update defaults to ON because retired/renamed models silently
// breaking dropdowns is a real user pain point and the refresh is
// background-only with no UI interruption.
function getAutoUpdateModelsEnabled() {
  return localStorage.getItem('waxframe_auto_update_models') !== 'false';
}
function getAutoUpdateInterval() {
  const v = localStorage.getItem('waxframe_auto_update_interval');
  return AUTO_UPDATE_INTERVALS[v] ? v : AUTO_UPDATE_DEFAULT_INTERVAL;
}
function getAutoUpdateIntervalMs() {
  return AUTO_UPDATE_INTERVALS[getAutoUpdateInterval()];
}
function getAutoUpdateLastRunMs() {
  const n = parseInt(localStorage.getItem(AUTO_UPDATE_LAST_RUN_KEY), 10);
  return Number.isFinite(n) ? n : 0;
}

// Settings-panel toggle handler. Writes the preference, surfaces a
// toast and a console line, greys out the interval row when off, and
// — when flipping ON — kicks off the scheduler immediately so a stale-
// by-now cache gets refreshed without waiting for the next work-screen
// entry.
function settingsToggleAutoUpdateModels(wantOn) {
  localStorage.setItem('waxframe_auto_update_models', wantOn ? 'true' : 'false');
  toast(wantOn
    ? '🔄 Auto-update model lists: on'
    : '🔄 Auto-update model lists: off — recheck rows manually', 3000);
  if (typeof consoleLog === 'function') {
    consoleLog(wantOn
      ? '🔄 Auto-update model lists enabled.'
      : '🔄 Auto-update model lists disabled — model dropdowns will persist until you click ↻ Recheck on each AI row.', 'info');
  }
  const row = document.getElementById('setAutoUpdateIntervalRow');
  if (row) row.classList.toggle('settings-row-disabled', !wantOn);
  if (wantOn) maybeRunAutoUpdateModels({ reason: 'toggled-on', force: true });
}

// Save handler for the interval radio. Persists the choice and surfaces
// the human label in the toast. Does NOT kick off an immediate refresh —
// changing the interval shouldn't fire a fetch, just change the cadence.
function saveAutoUpdateInterval(val) {
  if (!AUTO_UPDATE_INTERVALS[val]) val = AUTO_UPDATE_DEFAULT_INTERVAL;
  localStorage.setItem('waxframe_auto_update_interval', val);
  const labels = { '24h': '24 hours', '1w': '1 week', '30d': '30 days' };
  toast(`🔄 Auto-update interval: every ${labels[val]}`, 3000);
}

// v3.62.2 — Reset every "Don't show this again" dismissal so the
// associated confirms come back. Scans localStorage for any key with
// the waxframe_suppress_ prefix and clears each. Surfaces a count toast
// + console line so the user knows what happened.
function resetSuppressedPrompts() {
  let cleared = 0;
  try {
    const toRemove = [];
    for (let i = 0; i < localStorage.length; i++) {
      const k = localStorage.key(i);
      if (k && /^waxframe_suppress_/.test(k)) toRemove.push(k);
    }
    toRemove.forEach(k => { try { localStorage.removeItem(k); cleared++; } catch (e) {} });
  } catch (e) { /* quota / privacy mode */ }
  if (cleared > 0) {
    toast(`↺ Restored ${cleared} dismissed prompt${cleared === 1 ? '' : 's'}`, 3000);
    if (typeof consoleLog === 'function') {
      consoleLog(`👤 You restored ${cleared} dismissed confirmation prompt${cleared === 1 ? '' : 's'}.`, 'info');
    }
  } else {
    toast('Nothing to reset — no prompts are currently suppressed.', 3000);
  }
}

// ============================================================
//  v3.63.0 — Checkpoint Backup Nudge
//  v3.63.18 — Simplified: removed "Don't ask again for this project"
//             checkbox and the per-project localStorage suppression key.
//             Modal already fires only via initWorkScreen(true), which
//             skips on session restore — so in practice the checkbox
//             was suppressing an edge case (Back-from-work → Continue
//             round-trip in the same browser session) at the cost of
//             confusing copy in the modal ("Don't ask again" implied
//             the modal was a repeat offender; it isn't). Replaced
//             with a lightweight in-memory session flag that handles
//             the round-trip case without persistent state.
//
//  Fires ONCE PER PROJECT on the post-setup transition into the work
//  screen (initWorkScreen(true) only — never on session restore). The
//  goal is the pre-token-burn checkpoint: a free, fast moment to grab
//  a backup of the exact starting state, so if anything goes sideways
//  later (credit hiccup, unexpected drift, a different direction the
//  user wants to try without losing this one) the user can restore.
//
//  Two outcomes from the user's perspective:
//   1. Save Backup → runs the existing backupSession() flow
//   2. Not now    → in-memory dismissal for the rest of this browser
//                   session; the modal stays out of the way if the
//                   user does a Back-from-work → Continue round-trip
//                   that re-calls initWorkScreen(true). Closing and
//                   reopening WaxFrame resets the flag.
//
//  Orphan localStorage keys: any pre-v3.63.18 users who ticked the
//  removed "Don't ask again for this project" checkbox have
//  `waxframe_suppress_checkpoint_nudge__*` keys still in localStorage.
//  They are inert (no code reads them). Users who hit
//  resetSuppressedPrompts() ("Reset Dismissed Prompts" in settings)
//  will sweep them up — that function matches any `waxframe_suppress_`
//  prefix and clears the whole class in one pass.
// ============================================================

// v3.63.41 — First-run offer (merged). Was two stacked modals on first
// work-screen entry (checkpoint backup, then a separate save-as-template
// prompt). David: they should live in the same space. Now one modal with
// both options side by side + a single "Not now". No "don't ask again" —
// it's one-shot per session already (the dismissed flag below), so always
// ask. Picking an action closes the offer and runs that flow; both remain
// available afterward from the Tools menu / Finish panel.
// v3.63.62 — Don't auto-close on action click. Previous behavior:
// clicking Backup OR Template closed the modal, forcing the user to
// re-open Tools / Finish to do the OTHER one. Real intent is almost
// always "I want both, in sequence." Modal now stays up; clicking
// Backup runs the backup flow on top, clicking Template runs the
// template flow on top; the user dismisses the modal via "I'm done"
// (or the X) when they've taken whichever actions they want. Each
// child flow (sensitive-backup confirm, save-template modal) closes
// independently when done, returning the user to this modal.
async function maybeShowCheckpointBackupNudge() {
  if (window._checkpointNudgeDismissedThisSession) return;
  const m = document.getElementById('firstRunOfferModal');
  if (!m) return;
  m.classList.add('active');
}
function closeFirstRunOffer() {
  document.getElementById('firstRunOfferModal')?.classList.remove('active');
  window._checkpointNudgeDismissedThisSession = true;
}
function firstRunDoBackup() {
  // v3.63.62 → v3.63.238 — Originally kept the modal open so the user
  // could pick BOTH save-actions back-to-back. With v3.63.227's
  // modal-to-screen migration, backupSession() now navigates to the
  // dedicated Checkpoints screen, and a lingering nudge on top of
  // that screen is obstructive. Close the nudge on click; the
  // user can always reach the other action via the Tools menu.
  if (typeof closeFirstRunOffer === 'function') closeFirstRunOffer();
  if (typeof backupSession === 'function') backupSession();
}
function firstRunDoTemplate() {
  // v3.63.62 → v3.63.238 — Same change as firstRunDoBackup for
  // consistency: close the nudge so it doesn't sit on top of the
  // save-template modal. User can reach the other action (save
  // checkpoint) from the Tools menu if they want both.
  if (typeof closeFirstRunOffer === 'function') closeFirstRunOffer();
  if (typeof openSaveTemplateModal === 'function') openSaveTemplateModal();
}

// Internal: refresh ONE AI's model list without disturbing the picked
// model. Writes the fresh cache, returns { id, models, prevModel,
// stillPresent, error }. Designed to be tolerant of failures (per-AI
// errors don't abort the whole sweep).
async function _autoUpdateRefreshOneAI(ai) {
  const cfg = API_CONFIGS[ai.provider];
  if (!cfg) return { id: ai.id, error: 'no config' };
  // Skip AIs that have no key AND no models endpoint — nothing to fetch.
  const hasModelsEndpoint = !!cfg._modelsEndpoint;
  if (!cfg._key && !hasModelsEndpoint) {
    return { id: ai.id, skipped: 'no key' };
  }
  const format = cfg.format || 'openai';
  const isDefault = !!DEFAULT_AIS.find(d => d.id === ai.id);
  // Cache key matches the existing writer paths: default AIs key by
  // provider, customs key by AI id.
  const cacheKey = isDefault ? `waxframe_models_${ai.provider}` : `waxframe_models_${ai.id}`;
  const prevModel = cfg.model || '';
  try {
    const models = await fetchModelsFromEndpoint(cfg.endpoint, format, cfg._key, cfg._modelsEndpoint);
    if (!Array.isArray(models) || !models.length) {
      return { id: ai.id, error: 'no models returned' };
    }
    // v3.63.302 — Stamped via wfWriteVersioned (schema_version=1) so this
    // cache joins the per-key schema-versioning convention.
    window.wfWriteVersioned(cacheKey, { ts: Date.now(), models }, 1);
    // Detect retired selection: if the user's currently-picked model
    // isn't in the fresh list, surface the disappearance. We do NOT
    // change the selection — leaving the picked model as-is lets the
    // user decide whether to recheck (which picks a new one) or pick
    // manually from the new list.
    const stillPresent = !prevModel || models.includes(prevModel);
    return { id: ai.id, name: ai.name, models, prevModel, stillPresent };
  } catch (e) {
    return { id: ai.id, name: ai.name, error: e.message || String(e) };
  }
}

// Public: run a refresh sweep across every configured AI. Returns a
// summary object that callers can log. Per-AI errors are surfaced in
// the result but don't abort the sweep — one rate-limited provider
// shouldn't poison the whole pass.
async function refreshAllModelLists() {
  const ais = Array.isArray(aiList) ? aiList : [];
  if (!ais.length) return { refreshed: 0, retired: [], errors: [], skipped: [] };
  if (typeof consoleLog === 'function') {
    consoleLog(`🔄 Auto-Update: refreshing ${ais.length} model list${ais.length === 1 ? '' : 's'}…`, 'info');
  }
  const results = await Promise.all(ais.map(_autoUpdateRefreshOneAI));
  const refreshed = results.filter(r => r.models).length;
  const retired   = results.filter(r => r.models && !r.stillPresent);
  const errors    = results.filter(r => r.error);
  const skipped   = results.filter(r => r.skipped);
  if (typeof consoleLog === 'function') {
    const bits = [];
    if (refreshed) bits.push(`${refreshed} refreshed`);
    if (retired.length) bits.push(`${retired.length} with retired selection`);
    if (errors.length) bits.push(`${errors.length} errored`);
    if (skipped.length) bits.push(`${skipped.length} skipped`);
    consoleLog(`🔄 Auto-Update: ${bits.join(' · ') || 'no AIs to refresh'}`, retired.length || errors.length ? 'warn' : 'info');
    retired.forEach(r => consoleLog(`⚠️ ${r.name}: previously-selected model "${r.prevModel}" is no longer in the provider's list. Click ↻ Recheck on the AI row to pick a current model.`, 'warn'));
    errors.forEach(e => {
      consoleLog(`⚠️ ${e.name || e.id}: model-list refresh failed — ${e.error}`, 'warn');
      // v3.63.19 — friendly translation of the most common cause. Many
      // background API calls (Auto-Update, migrate-recommend, deprecation
      // watchdog) error with raw "HTTP 401" / "HTTP 403" text that means
      // nothing to a non-technical user. Auth-class errors map to "check
      // your API key" — anything else (rate limits, 5xx, network) is left
      // as the raw text since the right action depends on the specific
      // condition. Detection is on text shape from fetchModelsFromEndpoint's
      // thrown errors (the source of e.error here).
      if (/HTTP 401|HTTP 403|unauthorized|invalid.*key|authenticat/i.test(e.error || '')) {
        consoleLog(`💡 Please check the API key for ${e.name || e.id} — it may be invalid, expired, or rotated.`, 'info');
      }
    });
  }
  if (retired.length) {
    const names = retired.map(r => r.name).join(', ');
    toast(`⚠️ Retired model${retired.length === 1 ? '' : 's'} detected on: ${names}. Click ↻ Recheck on those AI rows.`, 6000);
  }
  // Stamp the last-run time only on a successful pass that actually
  // refreshed something. If nothing refreshed (all skipped/errored),
  // we want the NEXT scheduler tick to try again rather than wait the
  // full interval out from an empty pass.
  if (refreshed > 0) {
    try { localStorage.setItem(AUTO_UPDATE_LAST_RUN_KEY, String(Date.now())); } catch(e) {}
  }
  return { refreshed, retired, errors, skipped };
}

// Public dispatcher: called from work-screen entry and the in-screen
// interval timer. Gates on (a) the preference being on and (b) enough
// time having passed since the last run. opts.force bypasses the
// interval gate (used when the user toggles Auto-Update on).
async function maybeRunAutoUpdateModels(opts = {}) {
  if (!getAutoUpdateModelsEnabled()) return false;
  const now = Date.now();
  const lastRun = getAutoUpdateLastRunMs();
  const intervalMs = getAutoUpdateIntervalMs();
  const due = opts.force || (now - lastRun) >= intervalMs;
  if (!due) return false;
  // Reentrancy guard — if a refresh is already in flight, don't start a
  // second one (e.g. work-screen entry while a toggled-on sweep is
  // still resolving).
  if (window._autoUpdateInFlight) return false;
  window._autoUpdateInFlight = true;
  try {
    await refreshAllModelLists();
    return true;
  } finally {
    window._autoUpdateInFlight = false;
  }
}

// Interval timer started when the work screen mounts. Re-checks
// roughly every 15 minutes so a long-running session with no other
// navigation still triggers Auto-Update when its scheduled time
// passes. The actual fetch is gated by maybeRunAutoUpdateModels, so
// this is just a heartbeat.
let _autoUpdateHeartbeat = null;
function startAutoUpdateHeartbeat() {
  if (_autoUpdateHeartbeat) clearInterval(_autoUpdateHeartbeat);
  _autoUpdateHeartbeat = setInterval(() => {
    maybeRunAutoUpdateModels({ reason: 'heartbeat' });
  }, 15 * 60 * 1000);
}

// ── AUDIO ──
// v3.41.0 — All play* audio functions extracted to js/audio.js. Loaded
// after js/theme.js (depends on window._isMuted) and before app.js so
// the functions are globally available by the time anything here calls
// them. See audio.js for: playRoundCompleteSound, playAlertSound,
// playAlertIfUserDecisions, playAutoHaltSound, playSmokerSound,
// playBuilderSound, playRosieSound, playFlyingCarSound.


let _roundTimerInterval = null;
let _roundTimerStart    = null;
// v3.52.7 — _clockInterval removed (was declared "reserved for future
// use" but never wired to anything in 30+ releases).

function startRoundTimer(btn, baseLabel) {
  _roundTimerStart = Date.now();
  clearInterval(_roundTimerInterval);
  const clock   = document.getElementById('roundTimerDisplay');
  const labelEl = document.getElementById('roundTimerLabel');
  clock?.classList.add('running');
  labelEl?.classList.add('running');
  if (clock)   clock.textContent = '00:00';
  if (labelEl) labelEl.textContent = baseLabel.toUpperCase();
  const btnLabel = btn?.querySelector('.shake-wide-label');
  if (btnLabel) btnLabel.textContent = baseLabel;
  _roundTimerInterval = setInterval(() => {
    const secs = Math.floor((Date.now() - _roundTimerStart) / 1000);
    const m = String(Math.floor(secs / 60)).padStart(2, '0');
    const s = String(secs % 60).padStart(2, '0');
    if (clock) clock.textContent = `${m}:${s}`;
  }, 1000);
}

function stopRoundTimer() {
  clearInterval(_roundTimerInterval);
  _roundTimerInterval = null;
  _roundTimerStart    = null;
  const clock   = document.getElementById('roundTimerDisplay');
  const labelEl = document.getElementById('roundTimerLabel');
  clock?.classList.remove('running');
  labelEl?.classList.remove('running');
  if (clock)   clock.textContent = '00:00';
  if (labelEl) labelEl.textContent = 'READY';
}


// ── Project Clock (v3.63.197 — idle-aware) ──
// Behavior: clock auto-pauses after 60 sec of zero user input on the page,
// auto-resumes on next interaction. Distinguishes auto-idle-pause from
// user-manual-pause so that hitting the pause button stays sticky (does
// NOT auto-resume on next mouse move). David's call after the Joe Schmoe's
// run where the project clock reported 76 min "engaged" but the true
// engaged time was ~30 min — multitasking on phone/console/Claude while
// the session sat idle inflated the figure. This idle detection records
// honest engagement without requiring David to remember to hit Pause.
const _PROJ_CLOCK_IDLE_MS = 60_000;
let _projClockInterval     = null;
let _projClockSeconds      = 0;
let _projClockRunning      = false;
let _projClockUserPaused   = false;   // true if user clicked Pause manually
let _projClockIdlePaused   = false;   // true if auto-paused due to idle
let _projClockLastInputTs  = Date.now();
let _projClockIdleChecker  = null;

function _projClockRender() {
  const el = document.getElementById('projectTimerDisplay');
  if (!el) return;
  const h = Math.floor(_projClockSeconds / 3600);
  const m = Math.floor((_projClockSeconds % 3600) / 60);
  const s = _projClockSeconds % 60;
  el.textContent = `${String(h).padStart(2,'0')}:${String(m).padStart(2,'0')}:${String(s).padStart(2,'0')}`;
}

function _projClockUpdateButtons() {
  const startBtn = document.getElementById('projClockStartBtn');
  const pauseBtn = document.getElementById('projClockPauseBtn');
  if (startBtn) startBtn.classList.toggle('active', _projClockRunning);
  if (pauseBtn) pauseBtn.classList.toggle('active', !_projClockRunning && _projClockSeconds > 0);
  const display = document.getElementById('projectTimerDisplay');
  if (display) {
    display.classList.toggle('running', _projClockRunning);
    display.classList.toggle('paused', !_projClockRunning && _projClockSeconds > 0);
  }
}

// One-time wiring of global input listeners + idle checker. Called lazily
// from projectClockStart so we don't burn the listeners until the user
// has actually started a session. Idempotent — safe to call repeatedly.
function _projClockEnsureIdleWiring() {
  if (_projClockIdleChecker) return;
  const onInput = () => {
    _projClockLastInputTs = Date.now();
    // Auto-resume if we paused due to idle. Manual user-pause stays sticky.
    if (_projClockIdlePaused && !_projClockUserPaused) {
      _projClockIdlePaused = false;
      _projClockStartInternal();
    }
    // Attention escalation always clears on any user input — see _attention*.
    if (typeof _attentionClear === 'function') _attentionClear();
  };
  // Capture phase so we don't depend on bubbling through specific elements.
  ['pointerdown', 'keydown', 'wheel', 'scroll', 'touchstart'].forEach(ev => {
    window.addEventListener(ev, onInput, { capture: true, passive: true });
  });
  // Check every 5 sec — cheap, low jitter, no impact on the per-second tick.
  _projClockIdleChecker = setInterval(() => {
    if (!_projClockRunning) return;
    if (_projClockUserPaused) return;
    if (Date.now() - _projClockLastInputTs >= _PROJ_CLOCK_IDLE_MS) {
      _projClockPauseInternal({ idle: true });
    }
  }, 5000);
}

// Internal start (no user-flag changes). Used by both the public
// projectClockStart and the idle-resume path.
function _projClockStartInternal() {
  if (_projClockRunning) return;
  _projClockRunning = true;
  _projClockInterval = setInterval(() => {
    _projClockSeconds++;
    _projClockRender();
  }, 1000);
  _projClockUpdateButtons();
}

// Internal pause (idle: true means auto-pause from idle detection;
// idle: false means user clicked the Pause button).
function _projClockPauseInternal({ idle }) {
  if (!_projClockRunning) return;
  _projClockRunning = false;
  clearInterval(_projClockInterval);
  _projClockInterval = null;
  if (idle) _projClockIdlePaused = true;
  else      _projClockUserPaused = true;
  _projClockUpdateButtons();
}

function projectClockStart() {
  _projClockUserPaused = false;
  _projClockIdlePaused = false;
  _projClockLastInputTs = Date.now();
  _projClockEnsureIdleWiring();
  _projClockStartInternal();
}

function projectClockPause() {
  _projClockPauseInternal({ idle: false });
}

function projectClockReset() {
  _projClockRunning    = false;
  _projClockUserPaused = false;
  _projClockIdlePaused = false;
  clearInterval(_projClockInterval);
  _projClockInterval = null;
  _projClockSeconds  = 0;
  _projClockRender();
  _projClockUpdateButtons();
}

// ── Attention escalation (v3.63.197) ──
// When _autoHalt() fires (auto mode paused waiting for user decision), the
// existing playAutoHaltSound() makes one alert noise. If the user is set-
// and-forget multitasking (phone game, console, talking to Claude), they
// can miss that single chirp and leave the session hanging. After 5 min
// of no user input following the halt, escalate: flash the browser tab
// title between "🚨 WaxFrame Needs You!" and the original title every
// second, AND replay playAlertSound() every 30 sec until the user
// interacts with the page. Sound respects window._isMuted via the
// existing audio.js guard — escalation is silent if mute is on.
let _attentionTitleFlasher = null;
let _attentionSoundRepeater = null;
let _attentionFirstSoundDelay = null;
let _attentionOriginalTitle = '';

function _attentionStart() {
  _attentionClear();   // reset any prior state — single escalation at a time
  _attentionFirstSoundDelay = setTimeout(() => {
    // After 5 min: start flashing title + replay alert every 30 sec.
    _attentionOriginalTitle = document.title;
    let flip = false;
    _attentionTitleFlasher = setInterval(() => {
      flip = !flip;
      document.title = flip ? '🚨 WaxFrame Needs You!' : _attentionOriginalTitle;
    }, 1000);
    if (typeof playAlertSound === 'function') {
      try { playAlertSound(); } catch (e) {}
    }
    _attentionSoundRepeater = setInterval(() => {
      if (typeof playAlertSound === 'function') {
        try { playAlertSound(); } catch (e) {}
      }
    }, 30_000);
  }, 5 * 60 * 1000);
}

function _attentionClear() {
  if (_attentionFirstSoundDelay) { clearTimeout(_attentionFirstSoundDelay); _attentionFirstSoundDelay = null; }
  if (_attentionTitleFlasher)    { clearInterval(_attentionTitleFlasher);    _attentionTitleFlasher = null; }
  if (_attentionSoundRepeater)   { clearInterval(_attentionSoundRepeater);   _attentionSoundRepeater = null; }
  if (_attentionOriginalTitle) {
    document.title = _attentionOriginalTitle;
    _attentionOriginalTitle = '';
  }
}

function consoleLog(msg, type = 'info', rawData = null, link = null) {
  const el = document.getElementById('liveConsole');
  if (!el) return;
  // ── (v3.21.11) Strip the page-load default entry on first real log ──
  // The default "Console ready — Smoke the hive to begin." entry from
  // index.html stays in the DOM forever otherwise, because consoleLog
  // prepends new entries instead of replacing. That stale default
  // contaminated consoleHTML.includes(DEFAULT_CONSOLE_MSG) checks in
  // saveSession, causing Guard #1 to block every save after Round 1 —
  // which silently broke IDB persistence for every session since the
  // guard was added. Removing the default entry on first real activity
  // also matches the UX intent (it's only useful before anything happens).
  const defaultEntry = el.querySelector('.console-entry.console-info');
  if (defaultEntry && defaultEntry.textContent.includes('Smoke the hive to begin')) {
    defaultEntry.remove();
  }
  const entry = document.createElement('div');
  entry.className = `console-entry console-${type}`;
  const time = new Date().toLocaleTimeString([], {hour:'2-digit', minute:'2-digit', second:'2-digit'});
  const timeSpan = document.createElement('span');
  timeSpan.className = 'console-time';
  timeSpan.textContent = time + ' ';
  const msgSpan = document.createElement('span');
  msgSpan.textContent = msg.replace(/<[^>]+>/g, '');
  entry.appendChild(timeSpan);
  entry.appendChild(msgSpan);
  // v3.35.4 — Optional clickable link appended to console entry. Used
  // for actionable provider errors (credit-low, auth-failed, etc.) so
  // the user can click straight through to the provider console mid-
  // round without waiting for the round to finish. Built via DOM API
  // (createElement + textContent + href) so the URL/label cannot
  // inject HTML. The link is a sibling of the msgSpan, not part of
  // its text, so consoleHTML serialization to IDB still includes it
  // verbatim and reload restores the clickable state.
  // v3.35.5 — Native <a target="_blank"> click was getting eaten in
  // the work-screen layout (root cause not pinned — likely a
  // delegated handler or transparent overlay). Switched to explicit
  // window.open() onclick handler matching the working pattern in
  // renderTroubleshootingCard's button bindings (app.js:~506). The
  // href stays set as a fallback for middle-click, copy-link, and
  // screen readers, but the primary click path is the onclick.
  // v3.57.4 — P2: validate link.url through safeUrl() before it reaches the
  // href / window.open() sinks. link.url originates from ai.apiConsole, which on
  // a custom or imported AI can be arbitrary; safeUrl collapses anything that
  // isn't an absolute http(s) URL to '' so a javascript:/data: URL can't fire.
  const _safeLinkUrl = link ? safeUrl(link.url) : '';
  if (link && _safeLinkUrl && link.label) {
    const sep = document.createTextNode(' · ');
    const linkEl = document.createElement('a');
    linkEl.className = 'console-link external-link';
    linkEl.href = _safeLinkUrl;
    linkEl.target = '_blank';
    linkEl.rel = 'noopener';
    linkEl.textContent = link.label;
    // v3.63.304 — Inline boxed-arrow SVG (Kai spec v2). Built via
    // createElementNS (SVG needs the http://www.w3.org/2000/svg namespace)
    // so the function's v3.35.4 XSS safety stays intact — link.label is
    // still text-content only; no string interpolation reaches innerHTML.
    const _svgNs = 'http://www.w3.org/2000/svg';
    const _svg = document.createElementNS(_svgNs, 'svg');
    _svg.setAttribute('class', 'external-link-icon');
    _svg.setAttribute('viewBox', '0 0 24 24');
    _svg.setAttribute('aria-hidden', 'true');
    _svg.setAttribute('focusable', 'false');
    const _p1 = document.createElementNS(_svgNs, 'path');
    _p1.setAttribute('d', 'M14 3h7v7h-2V6.41l-9.29 9.3-1.42-1.42 9.3-9.29H14V3z');
    _svg.appendChild(_p1);
    const _p2 = document.createElementNS(_svgNs, 'path');
    _p2.setAttribute('d', 'M5 5h6v2H7v10h10v-4h2v6H5V5z');
    _svg.appendChild(_p2);
    linkEl.appendChild(_svg);
    const _srOnly = document.createElement('span');
    _srOnly.className = 'sr-only';
    _srOnly.textContent = '(opens in a new tab)';
    linkEl.appendChild(_srOnly);
    const url = _safeLinkUrl;
    linkEl.onclick = (e) => {
      e.preventDefault();
      e.stopPropagation();
      // Open a tab, not a Firefox pop-up window: passing a windowFeatures
      // string forces popup mode. Null the opener for the noopener benefit.
      const w = window.open(url, '_blank');
      if (w) { try { w.opener = null; } catch (_) {} }
    };
    entry.appendChild(sep);
    entry.appendChild(linkEl);
  }
  // Clickable arrow for error/warn entries that carry raw response data
  if (rawData && (type === 'error' || type === 'warn')) {
    const entryId = 'cle_' + Date.now() + '_' + Math.random().toString(36).slice(2,6);
    window._consoleErrorData[entryId] = rawData;
    const arrowBtn = document.createElement('button');
    arrowBtn.className = 'console-err-arrow';
    arrowBtn.textContent = '→';
    arrowBtn.title = 'Show raw response';
    arrowBtn.setAttribute('onclick', `openConsoleErrorDetail('${entryId}')`);
    entry.appendChild(arrowBtn);
  }
  el.prepend(entry);
}


// ── COPY / CLEAR HELPERS ──
// Single entry point for Copy buttons. Empty-state toast or success toast.
function copyToClipboard(text, label = 'Text', btn = null) {
  const txt = (text ?? '').toString();
  if (!txt.trim()) { toast(`⚠️ No ${label.toLowerCase()} to copy`); return; }
  // Resolve button reference: explicit arg, or the click event's currentTarget
  const button = btn || (typeof event !== 'undefined' ? event.currentTarget : null);
  navigator.clipboard.writeText(txt).then(
    () => {
      toast(`📋 ${label} copied`);
      flashCopyButton(button);
    },
    err => {
      // Promise rejection path — previously silent. Common causes: document
      // not focused, permissions denied, async context loss. Surface it.
      console.warn('[copy] writeText failed:', err);
      toast(`⚠️ Couldn't copy ${label.toLowerCase()} — click directly on the button and try again`);
    }
  );
}

// Brief green-check flash on a copy button to confirm the action visually,
// independent of the toast. Pass null and it's a no-op.
function flashCopyButton(btn) {
  if (!btn || !btn.classList) return;
  const original = btn.innerHTML;
  btn.classList.add('btn-copied');
  btn.innerHTML = '✓ Copied';
  setTimeout(() => {
    btn.classList.remove('btn-copied');
    btn.innerHTML = original;
  }, 1100);
}

function copyConsole() {
  const el = document.getElementById('liveConsole');
  if (!el) return;
  const text = Array.from(el.querySelectorAll('.console-entry')).reverse().map(e => e.textContent).join('\n');
  copyToClipboard(text, 'Console');
}

function copyConflicts() {
  copyToClipboard(document.getElementById('conflictsPanel')?.innerText, 'Conflicts');
}

function copyNotes() {
  copyToClipboard(document.getElementById('workNotes')?.value, 'Notes');
}

function clearNotes() {
  const ta = document.getElementById('workNotes');
  if (ta) ta.value = '';
  saveSession();
  updateNotesBtnPriority();
}

// v3.36.17 — Standing notes helpers. Mirror copyNotes / clearNotes
// but target the standing textarea. Standing notes don't influence
// the priority button glow (they inject every round automatically;
